1	type Quote = { premium: number };
2	type Item = { type: string; cursed?: boolean; enchantment?: number };
3	
4	const PROCESSING_FEE = 5;
5	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 100,
7	  staff: 80,
8	  amulet: 60,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	const ALIKE_BLOCK_SIZE = 3;
14	const ALIKE_BLOCK_PREMIUM = 60;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	
19	const basePremiumFor = (item: Item): number =>
20	  BASE_PREMIUM_BY_TYPE[item.type];
21	
22	const curseMultiplierFor = (item: Item): number =>
23	  item.cursed ? 1 + CURSE_SURCHARGE_RATE : 1;
24	
25	const enchantmentMultiplierFor = (item: Item): number =>
26	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
27	    ? 1 + HIGH_ENCHANTMENT_SURCHARGE_RATE
28	    : 1;
29	
30	const itemPremiumFor = (item: Item): number =>
31	  basePremiumFor(item) * curseMultiplierFor(item) * enchantmentMultiplierFor(item);
32	
33	const sumItemPremiums = (items: Item[]): number =>
34	  items.reduce((sum, item) => sum + itemPremiumFor(item), 0);
35	
36	const isAlikeBlock = (items: Item[]): boolean =>
37	  items.length === ALIKE_BLOCK_SIZE &&
38	  items.every((item) => item.type === items[0].type);
39	
40	const componentsPremium = (items: Item[]): number =>
41	  isAlikeBlock(items) ? ALIKE_BLOCK_PREMIUM : sumItemPremiums(items);
42	
43	export const quote = (input: { items: Item[] }): Quote => ({
44	  premium: componentsPremium(input.items) + PROCESSING_FEE,
45	});
46	
47	export const claim = (_input: unknown): unknown => undefined;
